import Vue from 'vue'
// import VueRouter from 'vue-router'
// import Login from '../components/login.vue'

const Login = () => import(/* webpackChunkName: "login_home_welcome" */ '../components/login.vue')
const Home = () => import(/* webpackChunkName: "login_home_welcome" */ '../components/home.vue')
const Welcome = () => import(/* webpackChunkName: "login_home_welcome" */ '../components/welcome.vue')

// import Home from '../components/home.vue'
// import Welcome from '../components/welcome.vue'

const User = () => import(/* webpackChunkName: "User_Power_Roles" */ '../components/user.vue')
const Power = () => import(/* webpackChunkName: "User_Power_Roles" */ '../components/power.vue')
const Roles = () => import(/* webpackChunkName: "User_Power_Roles" */ '../components/roles.vue')

// import User from '../components/user.vue'
// import Power from '../components/power.vue'
// import Roles from '../components/roles.vue'
// import Categories from '../components/category.vue'
// import Params from '../components/params.vue'

const Categories = () => import(/* webpackChunkName: "Categories_Params" */ '../components/category.vue')
const Params = () => import(/* webpackChunkName: "Categories_Params" */ '../components/params.vue')

// import List from '../components/list.vue'
// import Add from '../components/add.vue'

const List = () => import(/* webpackChunkName: "List_Add" */ '../components/list.vue')
const Add = () => import(/* webpackChunkName: "List_Add" */ '../components/add.vue')

// import Order from '../components/order.vue'
// import Reports from '../components/reports.vue'

const Order = () => import(/* webpackChunkName: "Order_Reports" */ '../components/order.vue')
const Reports = () => import(/* webpackChunkName: "Order_Reports" */ '../components/reports.vue')

Vue.use(VueRouter)

const routes = [
  {path:'/',redirect:'/login'},
  {path:'/login',component:Login},
  {
    path:'/home',
    component:Home,
    redirect:'/welcome',
    children:[
      {path:'/welcome',component:Welcome},
      {path:'/users',component:User},
      {path:'/rights',component:Power},
      {path:'/roles',component:Roles},
      {path:'/categories',component:Categories},
      {path:'/params',component:Params},
      {path:'/goods',component:List},
      {path:'/goods/add',component:Add},
      {path:'/orders',component:Order},
      {path:'/reports',component:Reports}
    ]
}
]

const router = new VueRouter({
  routes
})

// 挂在路由导航守卫
router.beforeEach((to,from,next)=>{
  if(to.path==='/login'){return next()}
  else{
    const token=window.sessionStorage.getItem("token")
    if(!token){
      console.log("error");
      return next('/login')
    }
    else{next()}
  }
})
export default router
